t.script:
        (() => {
  'use strict';

  const form = document.querySelector('.needs-validation');

  // Fungsi untuk menampilkan alert
  const showAlert = (message) => {
    const alertContainer = document.createElement('div');
    alertContainer.classList.add('alert-container');  // Menambahkan class untuk positioning
    const alertBox = document.createElement('div');
    alertBox.classList.add('alert', 'alert-danger', 'alert-dismissible', 'fade', 'show');
    alertBox.setAttribute('role', 'alert');

    const alertIcon = document.createElement('i');
    alertIcon.classList.add('bi', 'bi-exclamation-circle-fill');
    alertBox.appendChild(alertIcon);

    const alertText = document.createElement('span');
    alertText.classList.add('ms-2');
    alertText.textContent = message;
    alertBox.appendChild(alertText);

    alertContainer.appendChild(alertBox);

    // Menambahkan alert ke body dan memastikan tampil di bagian atas tanpa menggeser elemen
    document.body.appendChild(alertContainer);

    // Menghapus alert setelah 3 detik
    setTimeout(() => {
      alertBox.classList.remove('show');
      alertBox.classList.add('fade');
      setTimeout(() => alertContainer.remove(), 500); // Hapus elemen setelah animasi selesai
    }, 3000); // Waktu 3 detik
  };

  // Navigasi antar langkah
  const goToStep = (currentStep, targetStep) => {
    document.getElementById(currentStep).style.display = 'none';
    document.getElementById(targetStep).style.display = 'block';
  };

  // Fungsi regex password
  const isValidPassword = (password) => {
    const passwordRegex = /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d).{8,}$/;
    return passwordRegex.test(password);
  };

  // Fungsi validasi untuk nomor telepon/WA
  const isValidPhoneNumber = (phoneNumber) => {
    const phoneRegex = /^\d+$/; // Regex untuk memastikan hanya angka
    return phoneRegex.test(phoneNumber);
  };

  // Validasi semua input dalam container
  const validateInputs = (container) => {
    const inputs = container.querySelectorAll('input, select, textarea');
    let isValid = true;

    inputs.forEach(input => {
      if (input.id === 'nik' || input.id === 'ktp_ayah' || input.id === 'ktp_ibu') {
        // Validasi khusus NIK, KTP
        if (input.value.length !== 16 || !/^\d+$/.test(input.value)) {
          input.classList.add('is-invalid');
          input.classList.remove('is-valid');
          isValid = false;
        } else {
          input.classList.remove('is-invalid');
          input.classList.add('is-valid');
        }
      } else if (input.id === 'password') {
        // Validasi khusus password dengan regex
        if (!isValidPassword(input.value)) {
          input.classList.add('is-invalid');
          input.classList.remove('is-valid');
          isValid = false;
        } else {
          input.classList.remove('is-invalid');
          input.classList.add('is-valid');
        }
      } else if (input.id === 'password2') {
         // Validasi khusus konfirmasi password
          const passwordInput = container.querySelector('#password');
          if (input.value === passwordInput.value && input.value.trim() !== '') {
              input.classList.remove('is-invalid');
              input.classList.add('is-valid');
          } else {
              input.classList.add('is-invalid');
              input.classList.remove('is-valid');
              isValid = false;
          }
      } else if (!input.checkValidity()) {
        // Validasi umum
        input.classList.add('is-invalid');
        input.classList.remove('is-valid');
        isValid = false;
      } else {
        input.classList.remove('is-invalid');
        input.classList.add('is-valid');
      }
    });

    return isValid;
  };

  // Validasi file input khusus untuk langkah terakhir
  const validateFileInputs = () => {
    const fileInputs = document.querySelectorAll('#containerDataBerkas input[type="file"]');
    let isValid = true;

    fileInputs.forEach(fileInput => {
      // Abaikan validasi jika input adalah SKHUN atau Surat Kesehatan
      if (fileInput.id === 'skhun' || fileInput.id === 'surat_kesehatan' || fileInput.id === 'ijazah' || fileInput.id === 'raport_terakhir') {
        return;
      }
      if (fileInput.files.length === 0) {
        fileInput.classList.add('is-invalid');
        fileInput.classList.remove('is-valid');
        isValid = false;
      } else {
        fileInput.classList.remove('is-invalid');
        fileInput.classList.add('is-valid');
      }
    });

    return isValid;
  };

  // Navigasi "Selanjutnya"
  document.querySelectorAll('.btn-next').forEach(button => {
    button.addEventListener('click', () => {
      const currentStep = button.closest('.container').id;
      const nextStep = button.dataset.next;
      const currentContainer = document.getElementById(currentStep);

      if (!validateInputs(currentContainer)) {
        Swal.fire({
          icon: 'warning',
          title: 'Perhatian',
          text: 'Terdapat data yang belum di isi.',
          confirmButtonText: 'OK',
        });
        return;
      }

      goToStep(currentStep, nextStep);
    });
  });

  // Navigasi "Kembali"
  document.querySelectorAll('.btn-prev').forEach(button => {
    button.addEventListener('click', () => {
      const currentStep = button.closest('.container').id;
      const prevStep = button.dataset.prev;
      goToStep(currentStep, prevStep);
    });
  });

  // Validasi real-time
  document.querySelectorAll('input, select, textarea').forEach(input => {
    input.addEventListener('input', () => {
      if (input.id === 'nik' || input.id === 'ktp_ayah' || input.id === 'ktp_ibu') {
        if (input.value.length === 16 && /^\d+$/.test(input.value)) {
          input.classList.remove('is-invalid');
          input.classList.add('is-valid');
        } else {
          input.classList.add('is-invalid');
          input.classList.remove('is-valid');
        }
      } else if (input.id === 'password') {
        if (isValidPassword(input.value)) {
          input.classList.remove('is-invalid');
          input.classList.add('is-valid');
        } else {
          input.classList.add('is-invalid');
          input.classList.remove('is-valid');
        }
      } else if (input.id === 'password2') {
        // Validasi khusus konfirmasi password
        const passwordInput = document.querySelector('#password');
        if (input.value === passwordInput.value && input.value.trim() !== '') {
            input.classList.remove('is-invalid');
            input.classList.add('is-valid');
        } else {
            input.classList.add('is-invalid');
            input.classList.remove('is-valid');
        }
      } else if (!input.checkValidity()) {
        input.classList.add('is-invalid');
        input.classList.remove('is-valid');
      } else {
        input.classList.remove('is-invalid');
        input.classList.add('is-valid');
      }
    });
  });

  // Tombol submit pada langkah terakhir
  const submitButton = document.querySelector('button[type="submit"]');
  submitButton.addEventListener('click', (event) => {
    event.preventDefault(); // Mencegah pengiriman form secara default

    const currentContainer = document.getElementById('containerDataBerkas');
    const isInputValid = validateInputs(currentContainer);
    const isFileValid = validateFileInputs();

    if (isInputValid && isFileValid) {
      // Periksa reCAPTCHA setelah semua data tervalidasi
      const recaptchaResponse = grecaptcha.getResponse();
      if (!recaptchaResponse) {
        // Jika reCAPTCHA tidak dicentang, tampilkan alert peringatan
        showAlert('Anda perlu menyelesaikan verifikasi CAPTCHA untuk melanjutkan.');
        return;
      }

      form.submit(); // Kirim form jika validasi berhasil
    } else {
      Swal.fire({
        icon: 'warning',
        title: 'Perhatian',
        text: 'Mohon lengkapi semua data dan berkas yang diperlukan sebelum mengirim form.',
        confirmButtonText: 'OK',
      });
    }
  });
})();





        $(document).ready(function() {
        // Pengaturan terjemahan manual untuk bahasa Indonesia
        $.datepicker.regional['id'] = {
        closeText: 'Tutup',
        prevText: 'Sebelumnya',
        nextText: 'Berikutnya',
        currentText: 'Hari Ini',
        monthNames: ['Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni', 'Juli', 'Agustus',
        'September', 'Oktober', 'November', 'Desember'],
        monthNamesShort: ['Jan', 'Feb', 'Mar', 'Apr', 'Mei', 'Jun', 'Jul', 'Agt', 'Sep', 'Okt',
        'Nov', 'Des'],
        dayNames: ['Minggu', 'Senin', 'Selasa', 'Rabu', 'Kamis', 'Jumat', 'Sabtu'],
        dayNamesShort: ['Min', 'Sen', 'Sel', 'Rab', 'Kam', 'Jum', 'Sab'],
        dayNamesMin: ['Mi', 'Se', 'Sa', 'Ra', 'Ka', 'Ju', 'Sa'],
        weekHeader: 'Ming',
        dateFormat: 'dd/mm/yy',
        firstDay: 0,
        isRTL: false,
        showMonthAfterYear: false,
        yearSuffix: ''
        };

        $.datepicker.setDefaults($.datepicker.regional['id']);

        // Inisialisasi Datepicker
        $("#tanggal_lahir").datepicker({
        changeMonth: true,
        changeYear: true,
        yearRange: "1900:" + new Date().getFullYear(),
        maxDate: new Date()
        });
        $("#tanggal_lahir_ayah").datepicker({
        changeMonth: true,
        changeYear: true,
        yearRange: "1900:" + new Date().getFullYear(),
        maxDate: new Date()
        });
        $("#tanggal_lahir_ibu").datepicker({
        changeMonth: true,
        changeYear: true,
        yearRange: "1900:" + new Date().getFullYear(),
        maxDate: new Date()
        });
        $("#wali_tgl_lahir").datepicker({
        changeMonth: true,
        changeYear: true,
        yearRange: "1900:" + new Date().getFullYear(),
        maxDate: new Date()
        });
        });

        document.getElementById('tanggal_lahir').addEventListener('keydown', function(e) {
            // Prevent Backspace and Delete keys
            if (e.key === 'Backspace' || e.key === 'Delete') {
                e.preventDefault();
                return false;
            }
        });
        document.getElementById('tanggal_lahir_ayah').addEventListener('keydown', function(e) {
            // Prevent Backspace and Delete keys
            if (e.key === 'Backspace' || e.key === 'Delete') {
                e.preventDefault();
                return false;
            }
        });
        document.getElementById('tanggal_lahir_ibu').addEventListener('keydown', function(e) {
            // Prevent Backspace and Delete keys
            if (e.key === 'Backspace' || e.key === 'Delete') {
                e.preventDefault();
                return false;
            }
        });
        document.getElementById('wali_tgl_lahir').addEventListener('keydown', function(e) {
            // Prevent Backspace and Delete keys
            if (e.key === 'Backspace' || e.key === 'Delete') {
                e.preventDefault();
                return false;
            }
        });

        // Prevent cut/copy/paste
        document.getElementById('tanggal_lahir').addEventListener('cut', function(e) {
            e.preventDefault();
            return false;
        });

        document.getElementById('tanggal_lahir').addEventListener('copy', function(e) {
            e.preventDefault();
            return false;
        });
        // Prevent cut/copy/paste
        document.getElementById('tanggal_lahir_ayah').addEventListener('cut', function(e) {
            e.preventDefault();
            return false;
        });

        document.getElementById('tanggal_lahir_ayah').addEventListener('copy', function(e) {
            e.preventDefault();
            return false;
        });
        // Prevent cut/copy/paste
        document.getElementById('tanggal_lahir_ibu').addEventListener('cut', function(e) {
            e.preventDefault();
            return false;
        });

        document.getElementById('tanggal_lahir_ibu').addEventListener('copy', function(e) {
            e.preventDefault();
            return false;
        });
        // Prevent cut/copy/paste
        document.getElementById('wali_tgl_lahir').addEventListener('cut', function(e) {
            e.preventDefault();
            return false;
        });

        document.getElementById('wali_tgl_lahir').addEventListener('copy', function(e) {
            e.preventDefault();
            return false;
        });

        const provinsiSelect = document.getElementById('provinsi_id');
        const kotaSelect = document.getElementById('kota_id');
        const kecamatanSelect = document.getElementById('kecamatan_id');

        // Filter kota berdasarkan provinsi
        provinsiSelect.addEventListener('change', function () {
        const selectedProvinsi = this.value;

        // Filter kota
        [...kotaSelect.options].forEach(option => {
        if (option.value === "" || option.dataset.propinsi === selectedProvinsi) {
        option.classList.remove('d-none');
        } else {
        option.classList.add('d-none');
        }
        });

        // Reset pilihan kota
        kotaSelect.value = "";
        kecamatanSelect.value = "";
        });

        // Filter kecamatan berdasarkan kota
        kotaSelect.addEventListener('change', function () {
        const selectedKota = this.value;

        // Filter kecamatan
        [...kecamatanSelect.options].forEach(option => {
        if (option.value === "" || option.dataset.kota === selectedKota) {
        option.classList.remove('d-none');
        } else {
        option.classList.add('d-none');
        }
        });

        // Reset pilihan kecamatan
        kecamatanSelect.value = "";
        });

        // Cari elemen body dengan class spesifik
        const bodyElement = document.querySelector('body.o_body_html.container.overflow-x-hidden');
        // Jika elemen ditemukan, hapus class "container"
        if (bodyElement) {
        bodyElement.classList.remove('o_body_html');
        bodyElement.classList.remove('container');
        }

        //favicon

        document.addEventListener('DOMContentLoaded', function () {
          // Membuat elemen link
          var linkElement = document.createElement('link');
          linkElement.rel = 'icon';
          linkElement.type = 'image/x-icon';
          linkElement.href = '/pesantren_pendaftaran/static/img/favicon.ico?v=1';

          // Menambahkan elemen ke dalam tag head
          document.head.appendChild(linkElement);

          // Inisialisasi Select2 untuk Provinsi
          $('#provinsi_id').select2({
              placeholder: 'Pilih Provinsi',
              allowClear: true,
              ajax: {
                url: '/get_provinsi',
                type: 'POST', // Gunakan POST jika diperlukan
                contentType: 'application/json', // Pastikan tipe konten JSON
                dataType: 'json', // Memastikan response diterima dalam format JSON
                data: function (params) {
                    return JSON.stringify({
                        query: params.term // Parameter pencarian
                    });
                },
                processResults: function (data) {
                    return {
                        results: data.map(function (item) {
                            return { id: item.id, text: item.name };
                        })
                    };
                }
              }
          });

          // Inisialisasi Select2 untuk Kota
          $('#kota_id').select2({
              placeholder: 'Pilih Kota',
              allowClear: true
          }).prop('disabled', true);

          // Inisialisasi Select2 untuk Kecamatan
          $('#kecamatan_id').select2({
              placeholder: 'Pilih Kecamatan',
              allowClear: true
          }).prop('disabled', true);

          // Event handler ketika Provinsi dipilih
          $('#provinsi_id').on('change', function () {
              const provinsi_id = $(this).val();

              if (provinsi_id) {

                  // Enable Kota jika Provinsi dipilih
                  $('#kota_id').prop('disabled', false);

                  $.ajax({
                      url: '/get_kota/' + provinsi_id,
                      type: 'POST',
                      contentType: 'application/json', // Pastikan tipe konten JSON
                      dataType: 'json',
                      success: function (data) {
                          const kotaSelect = $('#kota_id');
                          kotaSelect.empty();
                          kotaSelect.append('Pilih Kabupaten/Kota');
                          data.forEach(function (kota) {
                              kotaSelect.append(`${kota.name}`);
                          });

                          // Re-inisialisasi Select2 untuk Kota dan Kecamatan
                          kotaSelect.trigger('change');
                      }
                  });
              } else {
                // Disable Kota dan Kecamatan jika Provinsi tidak dipilih
                $('#kota_id').prop('disabled', true).empty().append('Pilih Kabupaten/Kota');
                $('#kecamatan_id').prop('disabled', true).empty().append('Pilih Kecamatan');
              }
          });

          // Event handler ketika Kota dipilih
          $('#kota_id').on('change', function () {
              const kota_id = $(this).val();
              console.log(kota_id)

              if (kota_id) {

                  // Enable Kecamatan jika Kota dipilih
                  $('#kecamatan_id').prop('disabled', false);

                  $.ajax({
                      url: '/get_kecamatan/' + kota_id,
                      type: 'POST',
                      contentType: 'application/json', // Pastikan tipe konten JSON
                      dataType: 'json',
                      success: function (data) {
                          const kecamatanSelect = $('#kecamatan_id');
                          kecamatanSelect.empty();
                          kecamatanSelect.append('Pilih Kecamatan');
                          data.forEach(function (kecamatan) {
                              kecamatanSelect.append(`${kecamatan.name}`);
                          });

                          // Re-inisialisasi Select2 untuk Kecamatan
                          kecamatanSelect.trigger('change');
                      }
                  });
              } else {
                // Disable Kecamatan jika Kota tidak dipilih
                $('#kecamatan_id').prop('disabled', true).empty().append('Pilih Kecamatan');
              }
          });
      });


      function togglePasswordVisibility() {
        // Ambil elemen input password
        const passwordInput = document.getElementById('password');
        // Ambil elemen ikon mata
        const eyeIcon = passwordInput.nextElementSibling.nextElementSibling;

        // Periksa tipe input, lalu ubah visibilitas dan ikon
        if (passwordInput.type === 'password') {
          passwordInput.type = 'text'; // Ubah ke teks untuk menampilkan password
          eyeIcon.classList.replace('fa-eye-slash', 'fa-eye'); // Ubah ikon menjadi mata tertutup
        } else {
          passwordInput.type = 'password'; // Ubah ke password untuk menyembunyikan password
          eyeIcon.classList.replace('fa-eye', 'fa-eye-slash'); // Ubah ikon menjadi mata terbuka
        }
      }

      function togglePassword2Visibility() {
        // Ambil elemen input password
        const passwordInput = document.getElementById('password2');
        // Ambil elemen ikon mata
        const eyeIcon = passwordInput.nextElementSibling.nextElementSibling;

        // Periksa tipe input, lalu ubah visibilitas dan ikon
        if (passwordInput.type === 'password') {
          passwordInput.type = 'text'; // Ubah ke teks untuk menampilkan password
          eyeIcon.classList.replace('fa-eye-slash', 'fa-eye'); // Ubah ikon menjadi mata tertutup
        } else {
          passwordInput.type = 'password'; // Ubah ke password untuk menyembunyikan password
          eyeIcon.classList.replace('fa-eye', 'fa-eye-slash'); // Ubah ikon menjadi mata terbuka
        }
      }

      function filterJenjang() {
        jenjang = document.getElementById('jenjang_id');

        nilaiJenjang = jenjang.options[jenjang.selectedIndex].text;

        nisn = document.getElementById('nisn');
        noticeNisn = document.getElementById('noticeNisn');

        asalSekolah = document.getElementById('asal_sekolah');
        noticeAsalSekolah = document.getElementById('asalSekolahNotice');
        asalAlamatSekolah = document.getElementById('alamat_asal_sek');
        noticeAlamatSekolah = document.getElementById('alamatSekolahNotice');
        asalTelpSekolah = document.getElementById('telp_asal_sek');
        noticeTelpSekolah = document.getElementById('teleponSekolahNotice');
        asalStatusSekolah = document.getElementById('status_sekolah_asal');
        noticeStatusSekolah = document.getElementById('statusSekolahNotice');
        asalNpsnSekolah = document.getElementById('npsn');
        noticeNpsnSekolah = document.getElementById('npsnNotice');

        pindahan_sd = document.getElementById('pindahan_sd');

        if( nilaiJenjang == 'KB (2-3 Tahun)' || nilaiJenjang == 'TK (4-5 Tahun)' || nilaiJenjang == 'SD TAHFIZH BILINGUAL' ) {
          noticeNisn.style.display = 'none';
          nisn.removeAttribute('required');
        }else {
          noticeNisn.style.display = 'inline';
          nisn.setAttribute('required', 'true');
        }

        if( nilaiJenjang == 'KB (2-3 Tahun)' || nilaiJenjang == 'TK (4-5 Tahun)' ) {
          noticeAsalSekolah.style.display = 'none';
          asalSekolah.removeAttribute('required');
          noticeAlamatSekolah.style.display = 'none';
          asalAlamatSekolah.removeAttribute('required');
          noticeTelpSekolah.style.display = 'none';
          asalTelpSekolah.removeAttribute('required');
          noticeStatusSekolah.style.display = 'none';
          asalStatusSekolah.removeAttribute('required');
          noticeNpsnSekolah.style.display = 'none';
          asalNpsnSekolah.removeAttribute('required');
        }else {
          noticeAsalSekolah.style.display = 'inline';
          asalSekolah.setAttribute('required', 'true');
          noticeAlamatSekolah.style.display = 'inline';
          asalAlamatSekolah.setAttribute('required', 'true');
          noticeTelpSekolah.style.display = 'inline';
          asalTelpSekolah.setAttribute('required', 'true');
          noticeStatusSekolah.style.display = 'inline';
          asalStatusSekolah.setAttribute('required', 'true');
          noticeNpsnSekolah.style.display = 'inline';
          asalNpsnSekolah.setAttribute('required', 'true');
        }

        if( nilaiJenjang == 'SD TAHFIZH BILINGUAL' ) {
          pindahan_sd.style.display = 'block';
        }else {
          pindahan_sd.style.display = 'none';
        }

      }

      // Ambil elemen radio dan field input
      const radioNoTelp = document.getElementById('pilih_no_telp');
      const radioEmail = document.getElementById('pilih_email');
      const fieldNoTelp = document.querySelector('.row-telp');
      const fieldEmail = document.querySelector('.row-email');
      const fieldPassword = document.querySelector('.row-password');
      const fieldPassword2 = document.querySelector('.row-password2');
      const inputNoTelp = document.getElementById('nomor_login');
      const inputEmail = document.getElementById('email');
      const inputPassword = document.getElementById('password');
      const inputPassword2 = document.getElementById('password2');
2
      // Tambahkan event listener untuk radio button
      radioNoTelp.addEventListener('change', () => {
        if (radioNoTelp.checked) {
          fieldNoTelp.style.display = 'block'; // Tampilkan field no telp
          fieldEmail.style.display = 'none';  // Sembunyikan field email
          fieldPassword.style.display = 'block';
          fieldPassword2.style.display = 'block';
          inputNoTelp.required = true;         // Tambahkan atribut required
          inputEmail.required = false;        // Hapus atribut required
          inputPassword.required = true;        // Hapus atribut required
          inputPassword2.required = true;        // Hapus atribut required
        }
      });

      radioEmail.addEventListener('change', () => {
        if (radioEmail.checked) {
          fieldEmail.style.display = 'block'; // Tampilkan field email
          fieldNoTelp.style.display = 'none'; // Sembunyikan field no telp
          fieldPassword.style.display = 'block';
          fieldPassword2.style.display = 'block';
          inputEmail.required = true;        // Hapus atribut required
          inputNoTelp.required = false;         // Tambahkan atribut required
          inputPassword.required = true;        // Hapus atribut required
          inputPassword2.required = true;        // Hapus atribut required
        }
      });
